# DO NOT modify or add any import statementsfrom support import *ALL_WORDS = load_words("words.txt")# Name: Advaith Das Maharana# Student Number: s5010578# Favorite Word: # -----------------------------------------------------------------------------# Define your functions here# Task 1 ----------------------------------------------------------------------def num_hours() -> float:    """    Returns the number of hours spent on the assignment.    Returns:        float: Time spent in hours.    """        return 10.0 # Return any float value# Task 2 ----------------------------------------------------------------------def has_won(guess: str, target: str) -> bool:    """    Checks if the guess matches the target word.    Args:        guess (str): The guessed word.        target (str): The secret word.    Returns:        bool: True if guess is correct, False otherwise.    """        return guess == target# Task 3 ----------------------------------------------------------------------def get_max_guesses() -> int:    """    Prompts the user to enter a valid number of guesses.    Returns:        int: A number between 5 and 9.    """        # keep asking until a valid number is entered    while True:        guess = input(GET_NUM_GUESSES_MESSAGE)        if guess.isdigit():            value = int(guess)            if 5 <= value <= 9:                return value# Task 4 ----------------------------------------------------------------------def create_board(max_guesses: int) -> list[tuple[str, str]]:    """    Creates an empty board for the game.    Args:        max_guesses (int): Number of guesses allowed.    Returns:        list[tuple[str, str]]: Board with empty guesses and feedback.    """        empty = EMPTY * 6    board = []        # fill board with empty guess and feedback pairs    for _ in range(max_guesses):        board.append((empty, empty))    return board# Task 5 ----------------------------------------------------------------------def display_board(board: list[tuple[str, str]]) -> None:    """    Displays the current game board.    Args:        board (list[tuple[str, str]]): The game board.    """        for i, (guess, feedback) in enumerate(board):        print(SEP)        print(f"Guess {i + 1}:  {guess}")        print(f"Feedback: {feedback}")    print(SEP)# Task 6 ----------------------------------------------------------------------def generate_secret_word() -> str:    """    Selects a random word from the word list.    Returns:        str: The secret word.    """        index = randint(0, len(ALL_WORDS) - 1)    return ALL_WORDS[index]# Task 7 ----------------------------------------------------------------------def validate_input(command: str) -> bool:    """    Validates a user input command or guess.    Args:        command (str): User input.    Returns:        bool: True if valid, False otherwise.    """        if command in HELP_COMMAND or command in QUIT_COMMAND or command in KEYBOARD_COMMAND:        return True        # check for correct length and alphabetic characters    if len(command) != 6 or not command.isalpha():        print(INVALID_FORMAT_MESSAGE)        return False        # ensure all characters are lowercase and unique    if not command.islower() or len(set(command)) != 6:        print(INVALID_CHARACTERS_MESSAGE)        return False        # check if the word exists in the allowed word list    if command not in ALL_WORDS:        print(INVALID_GUESS_MESSAGE)         return False    return True# Task 8 ----------------------------------------------------------------------def get_command() -> str:    """    Prompts the user for a command or guess.    Returns:        str: A valid command or guess.    """        # keep asking until a valid command or guess is entered    while True:        command = input(ENTER_COMMAND_MESSAGE)        if command in HELP_COMMAND or command in QUIT_COMMAND or command in KEYBOARD_COMMAND:            return command        if validate_input(command):            return command# Task 9 ----------------------------------------------------------------------def get_feedback(guess: str, target: str) -> str:    """    Generates feedback for a guess.    Args:        guess (str): The guessed word.        target (str): The secret word.    Returns:        str: Feedback string using G, Y, and B.    """        feedback = ""        # compare each letter and assign feedback    for i in range(GUESS_LENGTH):        if guess[i] == target[i]:            feedback += GREEN        elif guess[i] not in target:            feedback += BLACK        else:            feedback += YELLOW    return feedback# Task 10 ----------------------------------------------------------------------def update_board(board: list[tuple], guess_num: int, guess: str, target: str) -> None:    """    Updates the board with a new guess.    Args:        board (list[tuple]): The game board.        guess_num (int): Current guess number.        guess (str): The guessed word.        target (str): The secret word.    """        feedback = get_feedback(guess, target)    board[guess_num - 1] = (guess, feedback)# Task 11 ---------------------------------------------------------------------def display_keyboard(keyboard: dict[str, str]) -> None:    """    Displays the keyboard with letter statuses.    Args:        keyboard (dict[str, str]): Keyboard mapping.    """        print("Keyboard:")    print(SEP)    count = 0        # print keyboard in rows of 3 letters    for key in keyboard:        value = keyboard[key]        print(f"{key}: {value}", end="    ")        count += 1        if count % 3 == 0:            print()    if count % 3 != 0:        print()    print(SEP)# Task 12 ---------------------------------------------------------------------def update_keyboard(board: list[tuple], keyboard: dict[str, str], guess_num: int) -> None:    """    Updates keyboard based on feedback.    Args:        board (list[tuple]): The game board.        keyboard (dict[str, str]): Keyboard mapping.        guess_num (int): Current guess number.    """        guess, feedback = board[guess_num - 1]        # update keyboard based on latest guess feedback    for i in range(len(guess)):        letter = guess[i]        status = feedback[i]        if status == GREEN:            keyboard[letter] = GREEN        elif status == YELLOW:            if keyboard[letter] != GREEN:                keyboard[letter] = YELLOW        else:            if keyboard[letter] == EMPTY:                keyboard[letter] = BLACK                                # Task 13 ---------------------------------------------------------------------def play_game() -> None:    """    Runs one full game of Weirdle.    """        print(WELCOME_MESSAGE)    max_guesses = get_max_guesses()    board = create_board(max_guesses)    keyboard = create_keyboard()    target = generate_secret_word()    guess_num = 1    display_board(board)         # main game loop handling user input and game state    while guess_num <= max_guesses:        command = get_command()        # display help instructions        if command in HELP_COMMAND:            print(HELP_MESSAGE)            continue                # show current keyboard status        elif command in KEYBOARD_COMMAND:            display_keyboard(keyboard)            continue        # exit the game immediately        elif command in QUIT_COMMAND:            return        # process a valid guess and update game state        else:            update_board(board, guess_num, command, target)            update_keyboard(board, keyboard, guess_num)            display_board(board)            if has_won(command, target):                print(WIN_MESSAGE)                return            guess_num += 1    print(f"{LOST_MESSAGE} The word was: {target}")        # Task 14 ---------------------------------------------------------------------def main() -> None:    """    Runs the program and handles replay.    """        while True:        play_game()        choice = input(RETRY_MESSAGE)        if choice != "Y" and choice != "y":            breakif __name__ == "__main__":    main()